 93 static bool bitTrackingDCE(Function &F, DemandedBits &DB) {
 94   SmallVector<Instruction*, 128> Worklist;
 95   bool Changed = false;
 96   for (Instruction &I : instructions(F)) {
 97     // If the instruction has side effects and no non-dbg uses,
 98     // skip it. This way we avoid computing known bits on an instruction
 99     // that will not help us.
100     if (I.mayHaveSideEffects() && I.use_empty())
101       continue;
102 
103     // Remove instructions that are dead, either because they were not reached
104     // during analysis or have no demanded bits.
105     if (DB.isInstructionDead(&I) ||
106         (I.getType()->isIntOrIntVectorTy() && DB.getDemandedBits(&I).isZero() &&
107          wouldInstructionBeTriviallyDead(&I))) {
108       Worklist.push_back(&I);
109       Changed = true;
110       continue;
111     }
112 
113     // Convert SExt into ZExt if none of the extension bits is required
114     if (SExtInst *SE = dyn_cast<SExtInst>(&I)) {
115       APInt Demanded = DB.getDemandedBits(SE);
116       const uint32_t SrcBitSize = SE->getSrcTy()->getScalarSizeInBits();
117       auto *const DstTy = SE->getDestTy();
118       const uint32_t DestBitSize = DstTy->getScalarSizeInBits();
119       if (Demanded.countl_zero() >= (DestBitSize - SrcBitSize)) {
120         clearAssumptionsOfUsers(SE, DB);
121         IRBuilder<> Builder(SE);
122         I.replaceAllUsesWith(
123             Builder.CreateZExt(SE->getOperand(0), DstTy, SE->getName()));
124         Worklist.push_back(SE);
125         Changed = true;
126         NumSExt2ZExt++;
127         continue;
128       }
129     }
130 
131     // Simplify and, or, xor when their mask does not affect the demanded bits.
132     if (auto *BO = dyn_cast<BinaryOperator>(&I)) {
133       APInt Demanded = DB.getDemandedBits(BO);
134       if (!Demanded.isAllOnes()) {
135         const APInt *Mask;
136         if (match(BO->getOperand(1), m_APInt(Mask))) {
137           bool CanBeSimplified = false;
138           switch (BO->getOpcode()) {
139           case Instruction::Or:
140           case Instruction::Xor:
141             CanBeSimplified = !Demanded.intersects(*Mask);
142             break;
143           case Instruction::And:
144             CanBeSimplified = Demanded.isSubsetOf(*Mask);
145             break;
146           default:
147             // TODO: Handle more cases here.
148             break;
149           }
150 
151           if (CanBeSimplified) {
152             clearAssumptionsOfUsers(BO, DB);
153             BO->replaceAllUsesWith(BO->getOperand(0));
154             Worklist.push_back(BO);
155             ++NumSimplified;
156             Changed = true;
157             continue;
158           }
159         }
160       }
161     }
162 
163     for (Use &U : I.operands()) {
164       // DemandedBits only detects dead integer uses.
165       if (!U->getType()->isIntOrIntVectorTy())
166         continue;
167 
168       if (!isa<Instruction>(U) && !isa<Argument>(U))
169         continue;
170 
171       if (!DB.isUseDead(&U))
172         continue;
173 
174       LLVM_DEBUG(dbgs() << "BDCE: Trivializing: " << U << " (all bits dead)\n");
175 
176       clearAssumptionsOfUsers(&I, DB);
177 
178       // Substitute all uses with zero. In theory we could use `freeze poison`
179       // instead, but that seems unlikely to be profitable.
180       U.set(ConstantInt::get(U->getType(), 0));
181       ++NumSimplified;
182       Changed = true;
183     }
184   }
185 
186   for (Instruction *&I : llvm::reverse(Worklist)) {
187     salvageDebugInfo(*I);
188     I->dropAllReferences();
189   }
190 
191   for (Instruction *&I : Worklist) {
192     ++NumRemoved;
193     I->eraseFromParent();
194   }
195 
196   return Changed;
197 }
